def reconcile_sources(sources):
    return all(s['n_in'] == s['n_clean'] + s['n_quarantine'] for s in sources)
print(reconcile_sources([
    {'n_in': 3, 'n_clean': 2, 'n_quarantine': 1},
    {'n_in': 2, 'n_clean': 2, 'n_quarantine': 0},
]))
print(reconcile_sources([{'n_in': 2, 'n_clean': 2, 'n_quarantine': 1}]))

def run(sources):
    if not all(s['n_in'] == s['n_clean'] + s['n_quarantine'] for s in sources):
        raise SystemExit('reconcile failed — fail closed')
    return {'status': 'publish_clean'}
try:
    print(run([{'n_in': 2, 'n_clean': 1, 'n_quarantine': 0}]))
except SystemExit as e:
    print('blocked', e)
print(run([{'n_in': 2, 'n_clean': 1, 'n_quarantine': 1}]))
